import{_ as t,o as n,c as s,a4 as l}from"./chunks/framework._in6GHBg.js";const u=JSON.parse('{"title":"解析几何套路","description":"","frontmatter":{},"headers":[],"relativePath":"math/Math-Review-Routine-006-解析几何套路-V1.0-20260405.md","filePath":"math/Math-Review-Routine-006-解析几何套路-V1.0-20260405.md"}'),e={name:"math/Math-Review-Routine-006-解析几何套路-V1.0-20260405.md"};function i(p,a,r,o,h,d){return n(),s("div",null,[...a[0]||(a[0]=[l(`<h1 id="解析几何套路" tabindex="-1">解析几何套路 <a class="header-anchor" href="#解析几何套路" aria-label="Permalink to &quot;解析几何套路&quot;">​</a></h1><p><strong>设点/设线→联立→韦达→翻译条件</strong></p><hr><h2 id="一、题型识别" tabindex="-1">一、题型识别 <a class="header-anchor" href="#一、题型识别" aria-label="Permalink to &quot;一、题型识别&quot;">​</a></h2><h3 id="特征关键词" tabindex="-1">特征关键词 <a class="header-anchor" href="#特征关键词" aria-label="Permalink to &quot;特征关键词&quot;">​</a></h3><ul><li>&quot;椭圆/双曲线/抛物线&quot;</li><li>&quot;直线与圆锥曲线相交&quot;</li><li>&quot;弦长&quot;</li><li>&quot;面积&quot;</li><li>&quot;定点/定值&quot;</li><li>&quot;中点&quot;</li></ul><h3 id="典型问法" tabindex="-1">典型问法 <a class="header-anchor" href="#典型问法" aria-label="Permalink to &quot;典型问法&quot;">​</a></h3><ul><li>求椭圆/抛物线的方程</li><li>证明直线过定点</li><li>求弦长的取值范围</li><li>求三角形面积的最大值</li><li>证明某值为定值</li></ul><hr><h2 id="二、解题步骤" tabindex="-1">二、解题步骤 <a class="header-anchor" href="#二、解题步骤" aria-label="Permalink to &quot;二、解题步骤&quot;">​</a></h2><h3 id="类型1-求圆锥曲线方程" tabindex="-1">类型1：求圆锥曲线方程 <a class="header-anchor" href="#类型1-求圆锥曲线方程" aria-label="Permalink to &quot;类型1：求圆锥曲线方程&quot;">​</a></h3><p><strong>Step 1：设方程</strong></p><ul><li>椭圆：x²/a² + y²/b² = 1（焦点在x轴）</li><li>抛物线：y² = 2px（开口向右）</li></ul><p><strong>Step 2：列条件</strong></p><ul><li>已知点代入</li><li>已知离心率e = c/a</li><li>已知焦点位置</li></ul><p><strong>Step 3：解方程组</strong></p><ul><li>利用a、b、c关系（椭圆：c²=a²-b²）</li></ul><hr><h3 id="类型2-直线与圆锥曲线相交-核心套路" tabindex="-1">类型2：直线与圆锥曲线相交（核心套路） <a class="header-anchor" href="#类型2-直线与圆锥曲线相交-核心套路" aria-label="Permalink to &quot;类型2：直线与圆锥曲线相交（核心套路）&quot;">​</a></h3><p><strong>Step 1：设直线方程</strong></p><p><strong>选择1：y = kx + m</strong></p><ul><li>适用：斜率存在，且不为0</li><li>注意：讨论斜率不存在的情况</li></ul><p><strong>选择2：x = my + n</strong></p><ul><li>适用：直线过x轴上定点，或需简化计算</li><li>避免斜率不存在的讨论</li></ul><p><strong>Step 2：联立方程</strong></p><ul><li>将直线方程代入圆锥曲线方程</li><li>消元得一元二次方程</li></ul><p><strong>Step 3：韦达定理</strong></p><ul><li>设交点A(x₁,y₁)、B(x₂,y₂)</li><li>x₁+x₂ = ...，x₁x₂ = ...</li><li>判别式Δ &gt; 0（保证相交）</li></ul><p><strong>Step 4：翻译条件</strong></p><ul><li>弦长：|AB| = √(1+k²)·|x₁-x₂|</li><li>中点：((x₁+x₂)/2, (y₁+y₂)/2)</li><li>斜率：k_AB = (y₂-y₁)/(x₂-x₁)</li></ul><p><strong>Step 5：化简求解</strong></p><hr><h3 id="类型3-弦长问题" tabindex="-1">类型3：弦长问题 <a class="header-anchor" href="#类型3-弦长问题" aria-label="Permalink to &quot;类型3：弦长问题&quot;">​</a></h3><p><strong>公式</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>|AB| = √(1+k²) · |x₁-x₂|</span></span>
<span class="line"><span>     = √(1+k²) · √[(x₁+x₂)² - 4x₁x₂]</span></span>
<span class="line"><span>     = √(1+k²) · √Δ/|a|</span></span></code></pre></div><p><strong>步骤</strong>：</p><ol><li>联立直线与曲线</li><li>用韦达定理表示x₁+x₂和x₁x₂</li><li>代入弦长公式</li><li>化简，求最值或范围</li></ol><hr><h3 id="类型4-面积问题" tabindex="-1">类型4：面积问题 <a class="header-anchor" href="#类型4-面积问题" aria-label="Permalink to &quot;类型4：面积问题&quot;">​</a></h3><p><strong>类型4.1：三角形面积</strong></p><p><strong>公式1（底×高）</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>S = (1/2) · |AB| · d</span></span></code></pre></div><ul><li>|AB|：弦长</li><li>d：点到直线的距离</li></ul><p><strong>公式2（坐标公式）</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>S = (1/2)|x₁y₂ - x₂y₁|</span></span></code></pre></div><p><strong>步骤</strong>：</p><ol><li>求弦长|AB|</li><li>求点C到直线AB的距离d</li><li>S = (1/2)|AB|·d</li><li>化为单变量函数，求最值</li></ol><p><strong>类型4.2：四边形面积</strong></p><ul><li>对角线垂直：S = (1/2)|AC|·|BD|</li><li>一般：分割成三角形</li></ul><hr><h3 id="类型5-定点问题" tabindex="-1">类型5：定点问题 <a class="header-anchor" href="#类型5-定点问题" aria-label="Permalink to &quot;类型5：定点问题&quot;">​</a></h3><p><strong>目标</strong>：证明直线过定点，或求定点坐标</p><p><strong>Step 1：设直线方程</strong></p><ul><li>y = kx + m 或 x = my + n</li></ul><p><strong>Step 2：联立，韦达</strong></p><p><strong>Step 3：利用条件</strong></p><ul><li>如：OA⊥OB → x₁x₂ + y₁y₂ = 0</li><li>如：k₁ + k₂ = 0（斜率互为相反数）</li></ul><p><strong>Step 4：化简得关系</strong></p><ul><li>得到k与m的关系</li></ul><p><strong>Step 5：代入直线方程</strong></p><ul><li>整理成y - y₀ = k(x - x₀)形式</li><li>定点即为(x₀, y₀)</li></ul><hr><h3 id="类型6-定值问题" tabindex="-1">类型6：定值问题 <a class="header-anchor" href="#类型6-定值问题" aria-label="Permalink to &quot;类型6：定值问题&quot;">​</a></h3><p><strong>目标</strong>：证明某表达式为定值</p><p><strong>Step 1：设变量</strong></p><ul><li>设直线斜率k或点的坐标</li></ul><p><strong>Step 2：表示目标式</strong></p><ul><li>用k表示目标表达式</li></ul><p><strong>Step 3：化简</strong></p><ul><li>若k消去，则为定值</li></ul><hr><h2 id="三、标准格式" tabindex="-1">三、标准格式 <a class="header-anchor" href="#三、标准格式" aria-label="Permalink to &quot;三、标准格式&quot;">​</a></h2><h3 id="直线与椭圆相交答题模板" tabindex="-1">直线与椭圆相交答题模板 <a class="header-anchor" href="#直线与椭圆相交答题模板" aria-label="Permalink to &quot;直线与椭圆相交答题模板&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>解：设直线方程为y = kx + m</span></span>
<span class="line"><span></span></span>
<span class="line"><span>联立：</span></span>
<span class="line"><span>{y = kx + m</span></span>
<span class="line"><span>{x²/a² + y²/b² = 1</span></span>
<span class="line"><span></span></span>
<span class="line"><span>消y得：(b² + a²k²)x² + 2a²kmx + a²(m²-b²) = 0</span></span>
<span class="line"><span></span></span>
<span class="line"><span>设A(x₁,y₁)，B(x₂,y₂)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>判别式：Δ = 4a²b²(b² + a²k² - m²) &gt; 0</span></span>
<span class="line"><span></span></span>
<span class="line"><span>韦达定理：</span></span>
<span class="line"><span>x₁ + x₂ = -2a²km/(b² + a²k²)</span></span>
<span class="line"><span>x₁x₂ = a²(m²-b²)/(b² + a²k²)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>[根据题目条件翻译]</span></span>
<span class="line"><span>...</span></span></code></pre></div><hr><h2 id="四、典型例题" tabindex="-1">四、典型例题 <a class="header-anchor" href="#四、典型例题" aria-label="Permalink to &quot;四、典型例题&quot;">​</a></h2><h3 id="例题1-弦长计算" tabindex="-1">例题1：弦长计算 <a class="header-anchor" href="#例题1-弦长计算" aria-label="Permalink to &quot;例题1：弦长计算&quot;">​</a></h3><p><strong>题目</strong>：直线y = x + 1与椭圆x²/4 + y² = 1相交于A、B两点，求|AB|。</p><p><strong>解答</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>解：联立：</span></span>
<span class="line"><span>{y = x + 1</span></span>
<span class="line"><span>{x²/4 + y² = 1</span></span>
<span class="line"><span></span></span>
<span class="line"><span>代入得：x²/4 + (x+1)² = 1</span></span>
<span class="line"><span>x²/4 + x² + 2x + 1 = 1</span></span>
<span class="line"><span>5x²/4 + 2x = 0</span></span>
<span class="line"><span>x(5x/4 + 2) = 0</span></span>
<span class="line"><span></span></span>
<span class="line"><span>∴ x₁ = 0，x₂ = -8/5</span></span>
<span class="line"><span>y₁ = 1，y₂ = -3/5</span></span>
<span class="line"><span></span></span>
<span class="line"><span>|AB| = √[(x₂-x₁)² + (y₂-y₁)²]</span></span>
<span class="line"><span>     = √[(64/25) + (64/25)]</span></span>
<span class="line"><span>     = 8√2/5</span></span></code></pre></div><hr><h3 id="例题2-定点问题" tabindex="-1">例题2：定点问题 <a class="header-anchor" href="#例题2-定点问题" aria-label="Permalink to &quot;例题2：定点问题&quot;">​</a></h3><p><strong>题目</strong>：椭圆x²/4 + y² = 1，过点P(0,1)的直线l交椭圆于A、B两点，证明：以AB为直径的圆过定点。</p><p><strong>解答</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>（略，涉及较复杂计算，展示套路即可）</span></span></code></pre></div><hr><h2 id="五、计算技巧" tabindex="-1">五、计算技巧 <a class="header-anchor" href="#五、计算技巧" aria-label="Permalink to &quot;五、计算技巧&quot;">​</a></h2><h3 id="技巧1-设线方式选择" tabindex="-1">技巧1：设线方式选择 <a class="header-anchor" href="#技巧1-设线方式选择" aria-label="Permalink to &quot;技巧1：设线方式选择&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:center;">情况</th><th style="text-align:left;">设线方式</th></tr></thead><tbody><tr><td style="text-align:center;">过y轴上定点(0,m)</td><td style="text-align:left;">y = kx + m</td></tr><tr><td style="text-align:center;">过x轴上定点(n,0)</td><td style="text-align:left;">x = ty + n（避免斜率不存在讨论）</td></tr><tr><td style="text-align:center;">斜率已知</td><td style="text-align:left;">点斜式</td></tr></tbody></table><h3 id="技巧2-韦达定理整体代入" tabindex="-1">技巧2：韦达定理整体代入 <a class="header-anchor" href="#技巧2-韦达定理整体代入" aria-label="Permalink to &quot;技巧2：韦达定理整体代入&quot;">​</a></h3><p>不要单独求x₁、x₂，用x₁+x₂和x₁x₂整体表示。</p><h3 id="技巧3-硬解定理-选学" tabindex="-1">技巧3：硬解定理（选学） <a class="header-anchor" href="#技巧3-硬解定理-选学" aria-label="Permalink to &quot;技巧3：硬解定理（选学）&quot;">​</a></h3><p>对于y = kx + m与x²/a² + y²/b² = 1：</p><ul><li>x₁+x₂ = -2a²km/(b²+a²k²)</li><li>x₁x₂ = a²(m²-b²)/(b²+a²k²)</li><li>弦长 = 2ab√[(1+k²)(b²+a²k²-m²)]/(b²+a²k²)</li></ul><hr><h2 id="六、易错点清单" tabindex="-1">六、易错点清单 <a class="header-anchor" href="#六、易错点清单" aria-label="Permalink to &quot;六、易错点清单&quot;">​</a></h2><h3 id="审题阶段" tabindex="-1">审题阶段 <a class="header-anchor" href="#审题阶段" aria-label="Permalink to &quot;审题阶段&quot;">​</a></h3><ul><li>[ ] 圆锥曲线类型是否看清？</li><li>[ ] 焦点位置是否确定？</li><li>[ ] 斜率是否存在是否需要讨论？</li></ul><h3 id="计算阶段" tabindex="-1">计算阶段 <a class="header-anchor" href="#计算阶段" aria-label="Permalink to &quot;计算阶段&quot;">​</a></h3><ul><li>[ ] 联立消元是否正确？</li><li>[ ] 判别式Δ是否计算？</li><li>[ ] 韦达定理符号是否正确？</li></ul><h3 id="检验阶段" tabindex="-1">检验阶段 <a class="header-anchor" href="#检验阶段" aria-label="Permalink to &quot;检验阶段&quot;">​</a></h3><ul><li>[ ] 结果是否合理？</li><li>[ ] 特殊情况是否验证？</li></ul><hr><h2 id="七、得分点提示" tabindex="-1">七、得分点提示 <a class="header-anchor" href="#七、得分点提示" aria-label="Permalink to &quot;七、得分点提示&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:center;">步骤</th><th style="text-align:left;">得分点</th></tr></thead><tbody><tr><td style="text-align:center;">设线</td><td style="text-align:left;">写出直线方程</td></tr><tr><td style="text-align:center;">联立</td><td style="text-align:left;">写出联立方程</td></tr><tr><td style="text-align:center;">韦达</td><td style="text-align:left;">写出x₁+x₂和x₁x₂</td></tr><tr><td style="text-align:center;">判别式</td><td style="text-align:left;">写出Δ&gt;0</td></tr><tr><td style="text-align:center;">翻译</td><td style="text-align:left;">将条件转化为代数式</td></tr></tbody></table><hr><p><strong>文档编号</strong>: Math-Review-Routine-006<br><strong>版本</strong>: V1.0<br><strong>日期</strong>: 20260405</p>`,107)])])}const x=t(e,[["render",i]]);export{u as __pageData,x as default};
